import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"黑暗光明永生仪式","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/黑暗光明永生仪式.md","filePath":"4.资源分区/6.技艺及称号/杂项/黑暗光明永生仪式.md"}'),d={name:"4.资源分区/6.技艺及称号/杂项/黑暗光明永生仪式.md"};function p(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"黑暗光明永生仪式",tabindex:"-1"},[s("黑暗光明永生仪式 "),e("a",{class:"header-anchor",href:"#黑暗光明永生仪式","aria-label":'Permalink to "黑暗光明永生仪式"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),o('<h1 id="黑暗光明永生仪式-1" tabindex="-1">黑暗光明永生仪式 <a class="header-anchor" href="#黑暗光明永生仪式-1" aria-label="Permalink to &quot;黑暗光明永生仪式&quot;">​</a></h1><p>黑暗/光明永生仪式<br> 价格：50<br> 前置要求：不能为光明/黑暗生物<br> 这是源于天堂地狱时期，阵营用来快速补充兵员的仪式，到现在经过数次改良，已经是简单易用而标准化的转化仪式了，仪式用到的所有材料，都可以在亚马逊上轻易买到。<br> 你可以在youtube上花25美元买到这一节课，上传者为-约翰 康斯坦丁。</p><p>在经过看起来似乎有点平平无奇的准备后，投掷一枚硬币（D2），受术者将连接地狱/天堂之门，召唤出一个下位生物来签订契约，以转化身份阵营为代价（随机成为黑暗生物/光明生物），获得不朽的生命，你的寿命不会被轻易地改变，这是一个C级的免疫衰老特性。<br> 在判断时，你需要先将硬币的正反面之一选择为地狱/天堂，另一面获得相反的含义。</p><p>这是个转换阵营的仪式，受术者只能完整进行一次仪式，即只能使用一次本资源，尝试多次购买来回转化阵营的25仔将面临天堂与地狱的双重怒火，永远的死去（撕卡）</p><p>特殊的，轮回者可以在购买此仪式和材料后，可以脱离主神空间自行进行仪式，但因为没有主神空间的阻拦，所以这种行为很难达成仪式本身具有的效果。</p><p>在非主神空间进行仪式，则人物需要进行一次自然骰，若出9及以下。则仅会召唤出仅仅对普通人有威胁的小恶魔，虽然无法给与你相应的仪式好处，但一般也不会对你造成什么损伤。若骰出10，则会召唤出更为强大的恶魔，就如同阿尔贝拉奎恩一样，虽然会得到收益，但也被迫签下完全不平等的条约。<br> 神与魔鬼不会撒谎，任意生物在举行仪式之初，便会清晰的知道这次仪式所所有真实情况与风险所在。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
